import { Router } from 'express';
import { OAUTH_PROVIDERS, OAuthProvider } from './oauth-config';
import { createPKCEPair } from './oauth-pkce';
import { signToken } from './jwt';
import { db } from '../db';

const router = Router();
const pendingPKCE = new Map<string, string>();

router.get('/oauth/:provider/authorize', (req, res) => {
  const provider = req.params.provider as OAuthProvider;
  const config = OAUTH_PROVIDERS[provider];
  if (!config) return res.status(400).json({ error: 'Unknown provider' });

  const pkce = createPKCEPair();
  const state = crypto.randomUUID();
  pendingPKCE.set(state, pkce.codeVerifier);

  const params = new URLSearchParams({
    client_id: config.clientId,
    redirect_uri: config.callbackUrl,
    response_type: 'code',
    scope: config.scopes.join(' '),
    state,
    code_challenge: pkce.codeChallenge,
    code_challenge_method: pkce.method,
  });

  res.redirect(`${config.authUrl}?${params}`);
});

router.get('/oauth/:provider/callback', async (req, res) => {
  const provider = req.params.provider as OAuthProvider;
  const config = OAUTH_PROVIDERS[provider];
  const { code, state } = req.query as { code: string; state: string };

  const codeVerifier = pendingPKCE.get(state);
  if (!codeVerifier) return res.status(400).json({ error: 'Invalid state' });
  pendingPKCE.delete(state);

  const tokenRes = await fetch(config.tokenUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded', Accept: 'application/json' },
    body: new URLSearchParams({
      grant_type: 'authorization_code',
      code,
      redirect_uri: config.callbackUrl,
      client_id: config.clientId,
      client_secret: config.clientSecret,
      code_verifier: codeVerifier,
    }),
  });

  const tokens = await tokenRes.json();
  // ... extract user info, upsert user, return JWT
  const user = await db.user.upsert({
    where: { email: '...' },
    create: { email: '...', oauthProvider: provider },
    update: { oauthProvider: provider },
  });
  const jwt = signToken(user.id);
  res.json({ token: jwt, expiresIn: '24h' });
});

export default router;

